cd /__w/eval-ont-agent-go/eval-ont-agent-go && perl -e '
open(my $fh, "<", "src/ontology/go-edit.obo") or die "Cannot open file";
my $term_count = 0;
my $in_term = 0;
my $line_num = 0;
while (<$fh>) {
  $line_num++;
  if (/^\[Term\]/) { $in_term = 1; $term_count++; }
  if (/^$/ && $in_term) { $in_term = 0; }
  if ($line_num > 100000) {
    print "File appears valid (checked first 100k lines, found $term_count terms)\n";
    last;
  }
}
close($fh);
print "Total terms found: $term_count\n" if $line_num >= 100000;
' 2>&1
